import{_ as t,o as a,c as i,am as s}from"./chunks/framework.foOaJFbm.js";const u=JSON.parse('{"title":"User Guide","description":"","frontmatter":{"title":"User Guide","description":"","navbar":true,"sideBar":true,"footer":false,"outline":[1,3],"editLink":false,"lastUpdated":true,"aside":"right","layout":"doc","custom":{},"hero":{"image":{"src":"","alt":"","width":"","height":""},"name":"VitePressSimple","text":"quick to config vitePress","description":"","tagline":"","actions":[],"features":[],"head":[]}},"headers":[],"relativePath":"user-guide/index.md","filePath":"user-guide/index.md","lastUpdated":1772429025000}'),o={name:"user-guide/index.md"};function n(r,e,l,d,c,m){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="functions-in-s-tide" tabindex="-1">Functions in S_TIDE <a class="header-anchor" href="#functions-in-s-tide" aria-label="Permalink to “Functions in S_TIDE”">​</a></h1><h2 id="for-documentation" tabindex="-1">FOR DOCUMENTATION <a class="header-anchor" href="#for-documentation" aria-label="Permalink to “FOR DOCUMENTATION”">​</a></h2><p>s_readme.m - this function briefly introduces all functions in S_TIDE</p><h2 id="for-demonstration" tabindex="-1">FOR DEMONSTRATION <a class="header-anchor" href="#for-demonstration" aria-label="Permalink to “FOR DEMONSTRATION”">​</a></h2><p>s_demo.m - demonstration codes for all functions in S_TIDE</p><h2 id="for-auxiliary-analysis" tabindex="-1">FOR AUXILIARY ANALYSIS <a class="header-anchor" href="#for-auxiliary-analysis" aria-label="Permalink to “FOR AUXILIARY ANALYSIS”">​</a></h2><p>s_plot_tidal_ellipse.m - plot tidal ellipse</p><p>s_plot_tidal_ellipse2.m - plot tidal ellipse at full depth</p><p>s_estimate_tidal_ellipse.m - calculate the parameters of tidal ellipse</p><p>s_construct.m - construct water levels by given tidal information without nodal factor/angle</p><p>s_nodal_cal.m - calculate the nodal factor and angle for given tides</p><p>s_construct2.m - construct water levels by given tidal information and nodal factor/angle (at middle time)</p><p>s_construct22.m - a revised version of s_construct2.m, which can simultaneously construct water levels at numerous locations.</p><p>s_construct3.m - construct water levels by given tidal information and nodal factor/angle (at each time)</p><p>s_tidalcharacter.m - calculate the basic tidal characters (such as skewness, high and low tides) from given water levels</p><p>s_alias.m - calculate the alias period caused by long-period satellite sampling</p><p>s_minimumLOR.m - calculate the minimum length of records to resolve given constituents</p><p>s_eot.m - function to read EOT20 tide models</p><p>s_equilibrium_tide.m - calculate equilibrium tidal levels</p><p>s_estimate_max_tidalcurrent.m - calculate the maximum possible tidal current speed with given N constituents</p><p>s_tdd.m - calculate the theoretical depth datum with given N constituents</p><p>s_rotation_spectra.m - calculate the rotation spectrum of currents</p><p>s_rtl.m - calculate the riding high/low tide levels from given water levels</p><p>s_rtl2.m - a modified version of s_rtl.m</p><p>s_modaldecomposition.m - dynamical modal decomposition for internal tides</p><p>s_modaldecomposition2.m - dynamical modal decomposition for internal tides,with regularization methods</p><p>s_earthtide.m - function to calculate theoretical earth tides/ocean tides potential</p><p>s_draw_tidalchart.m - function to draw co-tidal charts using EOT20 ocean tidal model</p><p>s_inertial.m - function to calculate the latitude which can generate near inertial oscillations whose frequencies are same as given tidal constituents</p><p>s_rS2.m - function to calculate radiational S2 tides from observed M2, S2, N2，K2 tides</p><p>s_wavelength.m - function to calculate the wave velocity and length of tidal constituents at given water depth</p><p>s_vector.m - function to realize vector operation (plus or minus)</p><p>s_tidetable.m - function to generate tide table with given hourly water level observations</p><p>s_HAreport.m - function to generate tidal analysis report (in the form of doc)</p><h2 id="for-tidal-harmonic-analysis" tabindex="-1">FOR TIDAL HARMONIC ANALYSIS <a class="header-anchor" href="#for-tidal-harmonic-analysis" aria-label="Permalink to “FOR TIDAL HARMONIC ANALYSIS”">​</a></h2><p>s_RHA.m - a revised harmonic analysis model which can consider non-astronomical external forcing (e.g. ENSO, Pan et al., 2025, doi: 10.1016/j.pocean.2024.103410)</p><p>s_MHACS - a modified harmonic analysis model designed for short-term tidal observations based on the credo of smoothness (Pan et al., 2023, doi: 10.1016/j.ocemod.2023.102251)</p><p>s_MHACS2 - an improved version of s_MHACS which can realize ridge regression and Lasso regression (Pan et al., 2024, doi: 10.1016/j.ocemod.2024.102372)</p><p>s_MHACSe - error estimation for MHACS</p><p>s_highlowtides - function to perform harmonic analysis for high and low tides (Pan et al., 2024, doi: 10.1016/j.csr.2024.105179)</p><p>s_quasi_HA.m - quasi harmonic analysis (for observations more than 24 hours but less than 13 days) using reference relationships from EOT20 model.</p><p>s_quasi_HA2.m - a revised version of s_quasi_HA for uneven observations</p><p>s_tide.m - computes the tidal analysis of the real tidal time series using Enhanced Harmonic Analysis (EHA) without nodal corrections. Users need to use s_nodal_correction function to nodally correct the amplitudes and phases.</p><p>s_tide_m1.m - a modified version of s_tide.m</p><p>s_tide_m2.m - a modified version of s_tide.m</p><p>s_tide_m3.m - a modified version of s_tide.m (for satellite data)</p><p>s_tide_m4.m - a modified version of s_tide.m (for satellite data)</p><p>s_tide_m5.m - a modified version of s_tide_m2.m (for uneven data)</p><p>s_tide_m55.m - a modified version of s_tide_m5.m (adding weights)</p><p>s_tide_m6.m - a modified version of s_tide_m4.m (for uneven satellite data)</p><p>s_tide_m66.m - a modified version of s_tide_m6.m (adding weights)</p><p>s_tide_m7.m - a modified version of s_tide.m which is designed specifically for estimating linear trends of tidal amplitudes and phases</p><p>s_tide_m8.m - a modified version of s_tide_m3.m (only uses nodal factor and angle at central time for nodal correction)</p><p>Notes: s_tide series functions use independent point (IP) scheme to obtain temporal variability of tidal parameters. For classical harmonic analysis, IP number should be set as 1, namely, tidal parameters are time-invariant. If IP number is set to 2, linear variations of tidal parameters can be obtained. The increase of IP number can induce more complicated variability in tidal parameters, but also increases the risk of over-fitting. For even tide gauge data, users can use s_tide_m8 function. For even/uneven satellite data, users can use s_tide_m4/s_tide_m6 function. For tidal current data, users need to analyze u and v respectively, and put tidal constants of u and v into s_estimate_tidal_ellipse function to calculate tidal ellipse parameters.</p>',54)])])}const _=t(o,[["render",n]]);export{u as __pageData,_ as default};
